 3→namespace App\Http\Controllers;
 4→
 5→use App\Services\AiAnalysisService;
 6→use Illuminate\Http\Request;
 7→use Illuminate\Support\Facades\Log;
 8→
 9→class AiController extends Controller
10→{
11→    /**
12→     * 通用 AI 对话接口，供 oa-server 调用。
13→     * 支持 blocking（返回 JSON）和 streaming（返回 SSE）两种模式。
14→     */
15→    public function chat(Request $request): mixed
16→    {
17→        $systemPrompt = $request->input('system_prompt', '');
18→        $message = $request->input('message', '');
19→        $responseMode = $request->input('response_mode', 'blocking');
20→        $history = $request->input('history', []);
21→
22→        Log::info('[lbl][0416-AI日报][AiChat][CALL] 收到AI对话请求', [
23→            'response_mode' => $responseMode,
24→            'message_len' => mb_strlen($message),
25→            'prompt_len' => mb_strlen($systemPrompt),
26→            'history_count' => count($history),
27→        ]);
28→
29→        if ($responseMode === 'streaming') {
30→            return response()->stream(function () use ($message, $systemPrompt, $history) {
31→                AiAnalysisService::app()->analyzeStream(
32→                    $message,
33→                    $systemPrompt,
34→                    function (string $chunk) {
35→                        echo 'data: '.json_encode([
36→                            'event' => 'message',
37→                            'answer' => $chunk,
38→                        ], JSON_UNESCAPED_UNICODE).PHP_EOL.PHP_EOL;
39→                        ob_flush();
40→                        flush();
41→                    },
42→                    $history
43→                );
44→                // 结束帧
45→                echo 'data: '.json_encode([
46→                    'event' => 'message_end',
47→                ], JSON_UNESCAPED_UNICODE).PHP_EOL.PHP_EOL;
48→                ob_flush();
49→                flush();
50→            }, 200, [
51→                'Content-Type' => 'text/event-stream',
52→                'Cache-Control' => 'no-cache',
53→                'X-Accel-Buffering' => 'no',
54→            ]);
55→        }
56→
57→        // Blocking mode
58→        $answer = AiAnalysisService::app()->analyze($message, $systemPrompt);
59→
60→        return response()->json([
61→            'error_code' => '0',
62→            'error_msg' => '',
63→            'data' => ['answer' => $answer],
64→        ]);
65→    }
66→}
