  3→namespace App\Services;
  4→
  5→use Illuminate\Support\Arr;
  6→use Illuminate\Support\Facades\Log;
  7→
  8→class AiAnalysisService
  9→{
 10→    use ServiceTrait;
 11→
 12→    /**
 13→     * Blocking 模式：调用 Vertex AI，返回完整分析结果。
 14→     * 用于邮件发送场景。
 15→     */
 16→    public function analyze(string $content, string $systemPrompt): string
 17→    {
 18→        [$endpoint, $model] = $this->getVertexConfig();
 19→        $accessToken = $this->getAccessToken();
 20→
 21→        if (empty($accessToken)) {
 22→            Log::error('[AiAnalysis] empty access token, abort');
 23→
 24→            return '';
 25→        }
 26→
 27→        $payload = json_encode([
 28→            'model' => $model,
 29→            'messages' => [
 30→                ['role' => 'system', 'content' => $systemPrompt],
 31→                ['role' => 'user', 'content' => $content],
 32→            ],
 33→            'stream' => false,
 34→        ], JSON_UNESCAPED_UNICODE);
 35→
 36→        Log::info('[AiAnalysis] blocking request', [
 37→            'content_len' => mb_strlen($content),
 38→            'prompt_len' => mb_strlen($systemPrompt),
 39→        ]);
 40→
 41→        $ch = curl_init($endpoint);
 42→        curl_setopt_array($ch, [
 43→            CURLOPT_POST => true,
 44→            CURLOPT_POSTFIELDS => $payload,
 45→            CURLOPT_HTTPHEADER => [
 46→                'Content-Type: application/json',
 47→                'Authorization: Bearer '.$accessToken,
 48→            ],
 49→            CURLOPT_RETURNTRANSFER => true,
 50→            CURLOPT_TIMEOUT => 120,
 51→        ]);
 52→
 53→        $response = curl_exec($ch);
 54→        $httpCode = curl_getinfo($ch, CURLINFO_HTTP_CODE);
 55→        $curlError = $response === false ? curl_error($ch) : '';
 56→        curl_close($ch);
 57→
 58→        if ($curlError) {
 59→            Log::error('[AiAnalysis] curl error', ['error' => $curlError]);
 60→            return '';
 61→        }
 62→
 63→        $result = json_decode($response, true);
 64→        if (!is_array($result)) {
 65→            Log::error('[AiAnalysis] invalid response', ['raw' => mb_substr($response, 0, 1000)]);
 66→            return '';
 67→        }
 68→
 69→        $answer = Arr::get($result, 'choices.0.message.content', '');
 70→        Log::info('[AiAnalysis] blocking done', ['answer_len' => mb_strlen($answer)]);
 71→
 72→        return $answer;
 73→    }
 74→
 75→    /**
 76→     * Streaming 模式：调用 Vertex AI，通过回调逐 chunk 输出。
 77→     * 用于测试 Prompt 和前端 SSE 场景。
 78→     *
 79→     * @param string $content 日报内容
 80→     * @param string $systemPrompt AI Prompt
 81→     * @param callable $onChunk fn(string $chunk): void 每个 chunk 的回调
 82→     * @param array $history 可选的历史对话消息
 83→     */
 84→    public function analyzeStream(string $content, string $systemPrompt, callable $onChunk, array $history = []): string
 85→    {
 86→        [$endpoint, $model] = $this->getVertexConfig();
 87→        $accessToken = $this->getAccessToken();
 88→
 89→        if (empty($accessToken)) {
 90→            Log::error('[AiAnalysis] empty access token, abort streaming');
 91→
 92→            return '';
 93→        }
 94→
 95→        $messages = [
 96→            ['role' => 'system', 'content' => $systemPrompt],
 97→        ];
 98→        foreach ($history as $msg) {
 99→            $messages[] = ['role' => $msg['role'], 'content' => $msg['content']];
100→        }
101→        if (!empty($content)) {
102→            $messages[] = ['role' => 'user', 'content' => $content];
103→        }
104→
105→        $payload = json_encode([
106→            'model' => $model,
107→            'messages' => $messages,
108→            'stream' => true,
109→        ], JSON_UNESCAPED_UNICODE);
110→
111→        Log::info('[AiAnalysis] streaming request', [
112→            'content_len' => mb_strlen($content),
113→            'prompt_len' => mb_strlen($systemPrompt),
114→            'history_count' => count($history),
115→        ]);
116→
117→        $fullReply = '';
118→        $buffer = '';
119→
120→        $ch = curl_init($endpoint);
121→        curl_setopt_array($ch, [
122→            CURLOPT_POST => true,
123→            CURLOPT_POSTFIELDS => $payload,
124→            CURLOPT_HTTPHEADER => [
125→                'Content-Type: application/json',
126→                'Authorization: Bearer '.$accessToken,
127→            ],
128→            CURLOPT_RETURNTRANSFER => false,
129→            CURLOPT_TIMEOUT => 300,
130→            CURLOPT_WRITEFUNCTION => function ($curl, $data) use (&$fullReply, &$buffer, $onChunk) {
131→                $buffer .= $data;
132→
133→                while (($pos = strpos($buffer, "\n")) !== false) {
134→                    $line = rtrim(substr($buffer, 0, $pos), "\r");
135→                    $buffer = substr($buffer, $pos + 1);
136→
137→                    if (!str_starts_with($line, 'data: ')) {
138→                        continue;
139→                    }
140→
141→                    $jsonStr = substr($line, 6);
142→                    if ($jsonStr === '[DONE]') {
143→                        continue;
144→                    }
145→
146→                    $decoded = json_decode($jsonStr, true);
147→                    if (!is_array($decoded)) {
148→                        continue;
149→                    }
150→
151→                    $chunk = Arr::get($decoded, 'choices.0.delta.content', '');
152→                    if ($chunk !== '') {
153→                        $fullReply .= $chunk;
154→                        $onChunk($chunk);
155→                    }
156→                }
157→
158→                return strlen($data);
159→            },
160→        ]);
161→
162→        curl_exec($ch);
163→        $curlError = curl_error($ch);
164→        curl_close($ch);
165→
166→        if ($curlError) {
167→            Log::error('[AiAnalysis] streaming curl error', ['error' => $curlError]);
168→        }
169→
170→        Log::info('[AiAnalysis] streaming done', ['reply_len' => mb_strlen($fullReply)]);
171→
172→        return $fullReply;
173→    }
174→
175→    /**
176→     * 通过 GCE Metadata Server 获取 Service Account 的 access token。
177→     * 参考：https://docs.cloud.google.com/vertex-ai/generative-ai/docs/samples/generativeaionvertexai-gemini-chat-completions-function-calling-config.
178→     */
179→    private function getAccessToken(): string
180→    {
181→        $url = 'http://metadata.google.internal/computeMetadata/v1/instance/service-accounts/default/token';
182→        $context = stream_context_create([
183→            'http' => [
184→                'header' => 'Metadata-Flavor: Google',
185→                'timeout' => 5,
186→            ],
187→        ]);
188→
189→        $response = @file_get_contents($url, false, $context);
190→        if ($response === false) {
191→            Log::error('[AiAnalysis] failed to get access token from metadata server');
192→
193→            return '';
194→        }
195→
196→        $data = json_decode($response, true);
197→
198→        return $data['access_token'] ?? '';
199→    }
200→
201→    /**
202→     * 拼接 Vertex AI OpenAI 兼容端点并返回配置。
203→     * 端点格式：https://{LOCATION}-aiplatform.googleapis.com/v1beta1/projects/{PROJECT_ID}/locations/{LOCATION}/endpoints/openapi/chat/completions.
204→     */
205→    private function getVertexConfig(): array
206→    {
207→        $projectId = config('vertex_ai.project_id');
208→        $location = config('vertex_ai.location', 'us-central1');
209→        $model = config('vertex_ai.model', 'google/gemini-2.5-flash');
210→
211→        $endpoint = "https://{$location}-aiplatform.googleapis.com/v1beta1/projects/{$projectId}/locations/{$location}/endpoints/openapi/chat/completions";
212→
213→        return [$endpoint, $model];
214→    }
215→}
