 8→
 9→// 允许跨域
10→if (!empty($_SERVER['HTTP_ORIGIN'])) {
11→    header('Access-Control-Allow-Origin: '.$_SERVER['HTTP_ORIGIN']);
12→    header('Access-Control-Allow-Credentials: true');
