16→}
17→
18→if (!empty($api_info)) {
19→    $prefix = $api_info['api_prefix'];
20→    $middlewares = $api_info['middlewares'];
21→
22→    Route::prefix($prefix)
23→        ->middleware($middlewares)
24→        ->group(function () use ($api_info) {
25→            Route::match($api_info['methods'], $api_info['api_uri'], $api_info['route']);
26→        });
27→}
28→
29→// 生产匹配所有 HTTP Method 的路由，miss 时抛一个 404
30→if (env('APP_ENV') === 'production') {
31→    Route::post('{path}', function () {
