45→            [
46→                'error_code' => ExceptionCode::ERR_USER_ROUTE_NOT_FOUND,
47→                'error_msg' => __(ExceptionCode::MESSAGES[ExceptionCode::ERR_USER_ROUTE_NOT_FOUND]),
48→                'data' => [],
49→            ],
50→            404
51→        );
52→    });
53→}
