  1→<?php
  2→/**
  3→ * 通用的帮助函数，不得抛出任何 HTTP 异常。
  4→ */
  5→
  6→use DateTime as DT;
  7→
  8→/**
  9→ * 时间格式。
 10→ */
 11→const MY_DATETIME_FORMAT = 'Y-m-d H:i:s';
 12→const MY_DATE_FORMAT = 'Y-m-d';
 13→const MY_TIME_FORMAT = 'H:i:s';
 14→
 15→if (!function_exists('my_datetime')) {
 16→    /**
 17→     * 获取预定义格式的时间。
 18→     *
 19→     * @param null $datetime
 20→     * @return string
 21→     */
 22→    function my_datetime($datetime = null): string
 23→    {
 24→        if (!is_null($datetime)) {
 25→            return date(MY_DATETIME_FORMAT, strtotime($datetime));
 26→        }
 27→
 28→        return date(MY_DATETIME_FORMAT);
 29→    }
 30→}
 31→
 32→if (!function_exists('my_date')) {
 33→    /**
 34→     * 获取预定义格式的日期。
 35→     *
 36→     * @param null $date
 37→     * @return string
 38→     */
 39→    function my_date($date = null): string
 40→    {
 41→        if (!is_null($date)) {
 42→            return date(MY_DATE_FORMAT, strtotime($date));
 43→        }
 44→
 45→        return date(MY_DATE_FORMAT);
 46→    }
 47→}
 48→
 49→if (!function_exists('my_time')) {
 50→    /**
 51→     * 获取预定义格式的时间。
 52→     *
 53→     * @param null $time
 54→     * @return string
 55→     */
 56→    function my_time($time = null): string
 57→    {
 58→        if (!is_null($time)) {
 59→            return date(MY_TIME_FORMAT, strtotime($time));
 60→        }
 61→
 62→        return date(MY_TIME_FORMAT);
 63→    }
 64→}
 65→
 66→if (!function_exists('diff_seconds')) {
 67→    /**
 68→     * 获取指定两个时间点的差值，以秒为单位。
 69→     *
 70→     * @param string $startTime
 71→     * @param string $endTime
 72→     * @return int
 73→     */
 74→    function diff_seconds(string $startTime, string $endTime): int
 75→    {
 76→        [$s, $e] = [strtotime($startTime), strtotime($endTime)];
 77→        return $e - $s;
 78→    }
 79→}
 80→
 81→if (!function_exists('diff_hours')) {
 82→    /**
 83→     * 获取时间差值，以小时为单位，支持整数和浮点数。
 84→     *
 85→     * @param string $startTime
 86→     * @param string $endTime
 87→     * @param bool $castToInt
 88→     * @return float|int
 89→     */
 90→    function diff_hours(string $startTime, string $endTime, bool $castToInt = true): float|int
 91→    {
 92→        $seconds = diff_seconds($startTime, $endTime);
 93→        $got = $seconds / 3600;
 94→
 95→        return $castToInt ? (int)($got) : $got;
 96→    }
 97→}
 98→
 99→if (!function_exists('diff_days')) {
100→    /**
101→     * 获取两个时间点的差值，以天数为单位。
102→     *
103→     * @param mixed $startTime
104→     * @param mixed $endTime
105→     * @throws \Exception
106→     * @return bool|int
107→     */
108→    function diff_days(mixed $startTime, mixed $endTime): bool|int
109→    {
110→        $startTime = new DT($startTime);
111→        $endTime = new DT($endTime);
112→        return $endTime->diff($startTime)->days;
113→    }
114→}
115→
116→if (!function_exists('current_shift_date')) {
117→    /**
118→     * 判断当前时间应该归属到排班的哪一天。
119→     *
120→     * @param null|mixed $time 既可以是 "+6 hours"，也可以是具体的时间，不传表示当前时间
121→     * @param string $boundaryTime 分界时间点，当前默认值为 6 点
122→     */
123→    function current_shift_date(mixed $time = null, string $boundaryTime = '06:00:00'): string
124→    {
125→        if ($time === null) {
126→            $time = date('H:i:s');
127→        }
128→
129→        // $boundaryTime - $time
130→        $beforeBoundary = diff_seconds(date("Y-m-d {$time}"), date("Y-m-d {$boundaryTime}")) > 0;
131→        return $beforeBoundary ? date('Y-m-d', strtotime('-1 day')) : date('Y-m-d');
132→    }
133→}
134→
135→if (!function_exists('valid_date')) {
136→    /**
137→     * 判断日期是否是合法的日期。
138→     *
139→     * @param string $date
140→     * @param array $formats
141→     * @return bool
142→     */
143→    function valid_date(string $date, array $formats = ['Y-m-d', 'Y/m/d']): bool
144→    {
145→        $unixTime = strtotime($date);
146→        if (!$unixTime) {
147→            return false;
148→        }
149→
150→        // 校验日期的有效性，只要满足其中一个格式即可
151→        foreach ($formats as $format) {
152→            if (date($format, $unixTime) == $date) {
153→                return true;
154→            }
155→        }
156→        return false;
157→    }
158→}
159→
160→if (!function_exists('current_api_info')) {
161→    /**
162→     * 解析指定 path，并返回该 path 命中的路由信息。
163→     *
164→     * @param string $path 请求的 path，e.g. web-api/home/login
165→     * @return array 当前请求命中的路由的详细信息
166→     */
167→    function current_api_info(string $path = ''): array
168→    {
169→        $path = empty($path) ? request()->path() : $path;
170→        $first = strpos($path, '/');
171→        $prefix = substr($path, 0, $first);
172→        $uri = trim(substr($path, $first), '/');
173→
174→        $routeConf = config("my_project.api_prefix_list.{$prefix}", []);
175→        if (empty($routeConf)) { // 找不到相应的 api_prefix 的话，返回空数组
176→            return [];
177→        }
178→
179→        $matchedRouteConfigFile = 'my_'.str_replace('-', '_', $prefix);
180→        $apiConf = config("{$matchedRouteConfigFile}.{$uri}");
181→
182→        // 默认同时支持 GET 和 POST 请求
183→        $methods = $apiConf['methods'] ?? ['get', 'post'];
184→
185→        // 合并 $routeConf 和 $apiConf 的中间件配置
186→        $middlewares = $routeConf['middlewares'];
187→        $middlewares = array_merge($middlewares, $apiConf['middlewares'] ?? []);
188→        $middlewares = array_diff($middlewares, $apiConf['skip_middlewares'] ?? []);
189→
190→        return [
191→            'api_prefix' => $prefix,
192→            'api_uri' => $uri,
193→            'methods' => $methods,
194→            'middlewares' => $middlewares,
195→            'route' => $apiConf['route'] ?? null,
196→            'params' => $apiConf['params'] ?? null,
197→            'owner_type' => $routeConf['owner_type'] ?? '',
198→            'auth_type' => $routeConf['auth_type'] ?? '',
199→        ];
200→    }
