288→if (!function_exists('operate_target_array')) {
289→    /**
290→     * `operate_target_array` 函数的功能是对数组`$target` 中的某些键值对进行一些操作，操作由 `$operation` 声明，键值对由
291→     * `$key` 和 `$value` 声明。其中，`$operation` 支持的动作如下所示：.
292→     *
293→     * + `replace` 替换指定路径处的元素
294→     * + `delete` 删除指定路径处的元素
295→     * + `add:*_suffix` 添加一个特定 key 的兄弟元素，* 代表原 key，新 key 为 `*_suffix`
296→     *
297→     * `$operation` 支持用 `|` 分割的多个动作，比如 `add:*_hash|delete` 会添加兄弟元素并删除原来的元素。
298→     *
299→     * @param array $target 目标数组
300→     * @param int|string $key 数组中的 key，因此必须为整形或者字符串
301→     * @param mixed $value key 对应的值
302→     * @param string $operation 所采取的动作
303→     * @throws InvalidArgumentException operation 非法时抛出一个异常
304→     * @return void
305→     */
306→    function operate_target_array(array &$target, int|string $key, mixed $value, string $operation): void
307→    {
308→        $operations = explode('|', $operation);
309→        foreach ($operations as $ope) {
310→            if ($ope === 'replace') { // 替换
311→                $target[$key] = $value;
312→            } elseif ($ope === 'delete') { // 删除
313→                unset($target[$key]);
314→            } elseif (str_starts_with($ope, 'add:')) { // 添加
315→                $newKey = str_replace('*', $key, substr($ope, 4));
316→                $target[$newKey] = $value;
317→            } else {
318→                throw new InvalidArgumentException('invalid operation given');
319→            }
320→        }
321→    }
322→}
