324→if (!function_exists('array_set_func')) {
325→    /**
326→     * `array_set_func` 是一个对数组中的某些键值对执行一些操作的方法，支持的具体操作见 `operate_target_array` 函数，`$func` 为
327→     * 一个闭包，会对旧的值进行转换，得到的新值会在 `$operation` 中包含 `add:*` 时添加到原数组中。
328→     *
329→     * `$options` 当前只支持设置 `skip_error` 来跳过错误。
330→     *
331→     * @param mixed $target 目标数组
332→     * @param string $path 指定路径，支持通配符，比如 `staffs.*.username`，支持 `$this` 代指 `$target` 本身
333→     * @param Closure $func 传 `null` 表示不执行函数，保留原值
334→     * @param null|string $operation 指定操作，默认 null 表示不做任何操作，一般用于 $func 第一个参数引用传递时
335→     * @param array $options 特殊选项，做一些运行时行为的控制，比如抑制报错
336→     * @throws InvalidArgumentException 传入的参数格式或者值错误
337→     * @return void
338→     */
339→    function array_set_func(mixed &$target, string $path, Closure $func, ?string $operation = null, array $options = []): void
340→    {
341→        $skipError = $options['skip_error'] ?? false;
342→        if (!is_array($target)) {
343→            if ($skipError) {
344→                return;
345→            }
346→            throw new InvalidArgumentException(sprintf('target must be an element of array type, got %s', gettype($target)));
347→        }
348→
349→        // 路径为 $this 表示直接对 $target 执行 $func 操作，此时 $func 的第一个参数一般是引用传递的
350→        if ($path === '$this') {
351→            $func($target);
352→            return;
353→        }
354→
355→        $segs = explode('.', $path);
356→        $seg = array_shift($segs);
357→
358→        // 取出第一端，* 表示通配，需要循环遍历每一个元素
359→        if ($seg === '*') {
360→            // 复制 target ，避免通过 operation 在 target 新增的元素进入循环
361→            $clone = $target;
362→            foreach ($clone as $key => $value) {
363→                if ($segs) { // 仍有后续路径的话，需继续递归
364→                    array_set_func($target[$key], implode('.', $segs), $func, $operation, $options);
365→                } else {
366→                    // 不存在后续路径，对每个元素进行回调操作
367→                    $funcReturn = $func($target[$key]);
368→                    if (!is_null($operation)) {
369→                        operate_target_array($target, $key, $funcReturn, $operation);
370→                    }
371→                }
372→            }
373→        } else {
374→            // 如果目标数组不包含该 key，则不再继续进行下去
375→            if (!array_key_exists($seg, $target)) {
376→                if ($skipError) {
377→                    return;
378→                }
379→                throw new RuntimeException(sprintf('missing key in target element: %s', $seg));
380→            }
381→
382→            $key = $seg;
383→            $value = &$target[$seg];
384→            if ($segs) { // 仍有后续路径的话，需继续递归
385→                array_set_func($value, implode('.', $segs), $func, $operation, $options);
386→            } else {
387→                $funcReturn = $func($value);
388→                if (!is_null($operation)) {
389→                    operate_target_array($target, $key, $funcReturn, $operation);
390→                }
391→            }
392→        }
393→    }
394→}
