396→if (!function_exists('array_set_func_recursive')) {
397→    /**
398→     * `array_set_func_recursive` 严格上来说不是 `array_set_func` 的递归版，`array_set_func` 本身就已经可以递归下去了。
399→     * `array_set_func_recursive` 引入了一个参数 `$rules` 来对所有符合规则的路径进行 `operate_target_array` 操作，而
400→     * 不是固定的符合 `path` 的元素进行相关操作。
401→     *
402→     * `$rules` 支持 `included_paths` 和 `excluded_paths` 两个参数，前者表示包含，后者表示排除，示例：
403→     *
404→     *    [
405→     *      "included_paths" => [
406→     *          "username",
407→     *      ],
408→     *      "excluded_paths" => [
409→     *          "username",
410→     *          "files.*.type", // 支持用 * 替代某个 key
411→     *          "exp*.A*G*Mn", // 支持用 * 替代某个 key 的一部分
412→     *      ],
413→     *   ]
414→     *
415→     * `$operate` 支持的操作见 `operate_target_array` 函数。
416→     *
417→     * @param array $target 目标数组（非数组直接返回）
418→     * @param array $rules
419→     * @param string $parentPath 记录父级路径
420→     * @param Closure $func
421→     * @param null|string $operation 指定操作，默认 null 表示不做任何操作（一般用于 $func 第一个参数引用传递时）
422→     * @throws InvalidArgumentException
423→     * @return void
424→     */
425→    function array_set_func_recursive(array &$target, array $rules, string $parentPath, Closure $func, ?string $operation = null): void
426→    {
427→        foreach ($target as $key => &$value) {
428→            // 当前路径不在“要包括的路径”中，同时在“要排除的路径”中，则直接跳过
429→            $currPath = empty($parentPath) ? $key : "{$parentPath}.{$key}";
430→            if (
431→                !match_paths($currPath, $rules['included_paths'])
432→                && match_paths($currPath, $rules['excluded_paths'])
433→            ) {
434→                continue;
435→            }
436→
437→            // $value 是数组的话，继续递归，否则执行 $func
438→            if (is_array($value)) {
439→                array_set_func_recursive($value, $rules, $currPath, $func, $operation);
440→            } else {
441→                $funcReturn = $func($value);
442→                if (!is_null($operation)) {
443→                    operate_target_array($target, $key, $funcReturn, $operation);
444→                }
445→            }
446→        }
447→    }
448→}
