450→if (!function_exists('match_paths')) {
451→    /**
452→     * 检查给定的路径是否存在于要匹配的路径列表中，以 . 分割路径段，支持用 * 替代某段路径或其一部分 (0~N个字符)，大小写敏感。
453→     * 以要匹配的表达式为基准进行前缀匹配，例：
454→     *     A.B != A.B.C
455→     *     A.B.C == A.B
456→     *     A.B.C != A*.C
457→     *     A.B.C == *A.*.C*
458→     *     A.a1Gm.C != A.a*g*m.C
459→     *     A.agkm.C.D == A.a*g*m.C.
460→     *
461→     * @param string $path 给定的字段路径，e.g. resume.0.username
462→     * @param array $list 要匹配的表达式列表，e.g. ['resume.*.gender', 'resume.*.birth_year']
463→     * @return bool
464→     */
465→    function match_paths(string $path, array $list): bool
466→    {
467→        $pathSegs = explode('.', $path);
468→        foreach ($list as $one) {
469→            $matchSegs = explode('.', $one);
470→            $flag = true;
471→            foreach ($matchSegs as $index => $seg) {
472→                // 给的路径中不存在该段，或给定路径中的该段不匹配，表示这条路径匹配失败
473→                if (!isset($pathSegs[$index]) || !fuzzy_match_str($pathSegs[$index], $seg)) {
474→                    $flag = false;
475→                    break;
476→                }
477→            }
478→
479→            if ($flag) {
480→                return true;
481→            }
482→        }
483→        return false;
484→    }
485→}
486→
487→if (!function_exists('fuzzy_match_str')) {
488→    /**
489→     * 模糊匹配字符串表达式，可用 * 替代 0~N 个任意字符，考虑使用 `fnmatch`?
490→     *
491→     * @param string $str 给定的字符串
492→     * @param string $exp 表达式
493→     * @return bool
494→     */
495→    function fuzzy_match_str(string $str, string $exp): bool
496→    {
497→        // 以 * 将目标表达式 $exp 分割为多段
498→        $expSegs = explode('*', $exp);
499→        $offset = 0;
500→        for ($i = 0; $i < count($expSegs); ++$i) {
501→            // 空段 (* 在首尾或连续多个 *) 直接跳过
502→            if ($expSegs[$i] === '') {
503→                continue;
504→            }
505→
506→            $startPos = strpos($str, $expSegs[$i], $offset);
507→            // 没搜索到某一段的话，匹配失败
508→            if ($startPos === false) {
509→                return false;
510→            }
511→
512→            // 第一段 (没有前导 *) 要求搜索到的开始位置必须是 $str 的开头
513→            if ($i === 0 && $startPos !== 0) {
514→                return false;
515→            }
516→
517→            $segLen = strlen($expSegs[$i]);
518→            // 最后一段 (没有后缀 *) 要求 $str 必须以 $expSegs[$i] 结尾
519→            if ($i === count($expSegs) - 1 && substr($str, -$segLen) !== $expSegs[$i]) {
520→                return false;
521→            }
522→
523→            // 将下一次搜索开始的位置移动到本次搜索结束的位置
524→            $offset = $startPos + $segLen;
525→        }
526→        return true;
527→    }
528→}
