 15→class DecryptService
 16→{
 17→    use ServiceTrait;
 18→
 19→    public static bool $useOldKey = false;
 20→
 21→    /**
 22→     * 标记解密过程中的异常是否需要抛出。
 23→     *
 24→     * @var bool
 25→     */
 26→    protected bool $throwEcp = false;
 27→
 28→    /**
 29→     * 解密混合文本时用于匹配加密字符串的正则表达式，e.g. `OFFER-##crypt:nothing#姓名密文:crypt##`。
 30→     *
 31→     * @var string
 32→     */
 33→    protected string $pattern = '/##crypt:(.*?)#(.*?):crypt##/';
 34→
 35→    /**
 36→     * 控制解密过程抛出异常。
 37→     *
 38→     * @param bool $throwEcp 是否抛出异常
 39→     * @return $this
 40→     */
 41→    public function throwEcp(bool $throwEcp = true): DecryptService
 42→    {
 43→        $this->throwEcp = $throwEcp;
 44→        return $this;
 45→    }
 46→
 47→    /**
 48→     * 对一批数据按配置参数进行解密。
 49→     *
 50→     * @param array $data 原始数据
 51→     * @param array $conf 解密配置
 52→     * @param string $operation 解密后要执行的操作：send_email|response
 53→     * @throws \App\Exceptions\CryptoException 各种原因导致的解密失败
 54→     * @return array 解密后的数据
 55→     */
 56→    public function decryptData(array $data, array $conf, string $operation): array
 57→    {
 58→        try {
 59→            array_set_func(
 60→                $data,
 61→                $conf['obj'],
 62→                function (array &$resObj) use ($conf, $operation) {
 63→                    $checkFunc = $this->getCheckFunc($conf, $operation);
 64→                    foreach ($conf['decrypt_columns'] ?? [] as $path) {
 65→                        // 用指定路径处的 value 执行 decryptValue 函数，并用函数返回值替换指定路径处的 value
 66→                        array_set_func(
 67→                            $resObj,
 68→                            $path,
 69→                            function ($value) use ($checkFunc) {
 70→                                if (!is_array($value)) {
 71→                                    return $this->decryptValue($value, $checkFunc);
 72→                                }
 73→                                // 数组类型的 $value，对其每一个子元素解密，不递归
 74→                                foreach ($value as &$one) {
 75→                                    $one = $this->decryptValue($one, $checkFunc);
 76→                                }
 77→                                return $value;
 78→                            },
 79→                            'replace',
 80→                            ['skip_error' => true] // 解密时允许指定了多余的字段
 81→                        );
 82→                    }
 83→
 84→                    // 处理部分解密的字段，通过正则表达式匹配出要解密的字符串，一般是邮件中的文本
 85→                    foreach ($conf['partly_decrypt_columns'] ?? [] as $path) {
 86→                        array_set_func(
 87→                            $resObj,
 88→                            $path,
 89→                            function ($value) use ($checkFunc) {
 90→                                if (!is_array($value)) {
 91→                                    return $this->decryptText($value, $checkFunc);
 92→                                }
 93→                                // 数组类型的 $value，对其每一个子元素解密，不递归
 94→                                foreach ($value as &$one) {
 95→                                    $one = $this->decryptText($one, $checkFunc);
 96→                                }
 97→                                return $value;
 98→                            },
 99→                            'replace',
100→                            ['skip_error' => true] // 解密时允许指定了多余的字段
101→                        );
102→                    }
103→                }
104→            );
105→        } catch (Exception $e) {
106→            throw new CryptoException('failed to decrypt data: '.$e->getMessage());
107→        }
108→        return $data;
109→    }
110→
111→    /**
112→     * 对一批数据按配置参数进行解密，不检查权限，目前只在命令行调用了，数据处理完可以清理掉。
113→     *
114→     * @param array $data 原始数据
115→     * @param array $conf 解密配置
116→     * @throws \App\Exceptions\CryptoException 各种原因导致的解密失败
117→     * @return array 解密后的数据
118→     */
119→    public function decryptDataFromConsole(array $data, array $conf): array
120→    {
121→        if (!App::runningInConsole()) {
122→            throw new CryptoException('must run in console.');
123→        }
124→
125→        try {
126→            array_set_func(
127→                $data,
128→                $conf['obj'],
129→                function (array &$resObj) use ($conf) {
130→                    foreach ($conf['decrypt_columns'] ?? [] as $path) {
131→                        // 用指定路径处的 value 执行 decryptValue 函数，并用函数返回值替换指定路径处的 value
132→                        array_set_func(
133→                            $resObj,
134→                            $path,
135→                            function ($value) {
136→                                if (!is_array($value)) {
137→                                    return $this->decryptValue($value);
138→                                }
139→                                // 数组类型的 $value，对其每一个子元素解密，不递归
140→                                foreach ($value as &$one) {
141→                                    $one = $this->decryptValue($one);
142→                                }
143→                                return $value;
144→                            },
145→                            'replace',
146→                            ['skip_error' => true] // 解密时允许指定了多余的字段
147→                        );
148→                    }
149→
150→                    // 处理部分解密的字段，通过正则表达式匹配出要解密的字符串，一般是邮件中的文本
151→                    foreach ($conf['partly_decrypt_columns'] ?? [] as $path) {
152→                        array_set_func(
153→                            $resObj,
154→                            $path,
155→                            function ($value) {
156→                                if (!is_array($value)) {
157→                                    return $this->decryptText($value);
158→                                }
159→                                // 数组类型的 $value，对其每一个子元素解密，不递归
160→                                foreach ($value as &$one) {
161→                                    $one = $this->decryptText($one);
162→                                }
163→                                return $value;
164→                            },
165→                            'replace',
166→                            ['skip_error' => true] // 解密时允许指定了多余的字段
167→                        );
168→                    }
169→                }
170→            );
171→        } catch (Exception $e) {
172→            throw new CryptoException('failed to decrypt data: '.$e->getMessage());
173→        }
174→        return $data;
175→    }
176→
177→    /**
178→     * 解密指定密文，并检查当前用户是否有该密文的权限.
179→     *
180→     * @param null|string $value 需要解密的密文
181→     * @param null|Closure $checkFunc 权限检查方法
182→     * @throws \App\Exceptions\CryptoException 解密失败时抛出异常
183→     * @return mixed 解密失败返回原值，并带上形如 [E:101] 的前缀
184→     */
185→    public function decryptValue(?string $value, ?Closure $checkFunc = null)
186→    {
187→        if (is_null($value) || $value === '') { // 空值不必解密
188→            return $value;
189→        }
190→
191→        try {
192→            $deStr = $this->decryptWithKey($value);
193→            if (empty($deStr)) {
194→                throw new CryptoException("openssl decrypt failed: {$value}", CryptoException::ERR_OPENSSL_DECRYPT_FAILED);
195→            }
196→
197→            $deInfo = ResourceMd::parseDecryptedStr($deStr);
198→            if (empty($deInfo)) {
199→                throw new CryptoException("decrypted str format error: {$value}", CryptoException::ERR_DECRYPTED_STR_FORMAT);
200→            }
201→
202→            try {
203→                $resMd = ResourceMd::find($deInfo['res_type'], $deInfo['res_id']);
204→            } catch (ResourceException $re) {
205→                throw new CryptoException($re->getMessage(), CryptoException::ERR_CRYPTO_RESOURCE_MESSING);
206→            }
207→
208→            // 检查当前用户是否有该密文的所有权
209→            if (!is_null($checkFunc)) {
210→                $checkFunc($resMd);
211→            }
212→        } catch (Exception $e) {
213→            if ($this->throwEcp) {
214→                throw new CryptoException($e->getMessage(), $e->getCode());
215→            }
216→
217→            Log::error(__METHOD__.' Exception: '.$e->getMessage());
218→
219→            $code = CryptoException::shortenCode($e->getCode());
220→            // openssl decrypt failed 可能是一个明文，直接返回该值即可
221→            $prefix = ($code === 0 || $code === CryptoException::ERR_OPENSSL_DECRYPT_FAILED) ? '' : "[E:{$code}]";
222→            return $prefix.$value;
223→        }
224→
225→        return $deInfo['value'];
226→    }
227→
228→    /**
229→     * 使用指定的 key 对称解密指定的 value。
230→     *
231→     * @param string $value
232→     * @param null|string $key
233→     * @return false|string
234→     */
235→    public function decryptWithKey(string $value, ?string $key = null)
236→    {
237→        if ($value === '') { // 空值不必解密
238→            return '';
239→        }
240→
241→        if (static::$useOldKey) {
242→            $key = config('my_project.hr_encrypt_key');
243→        }
244→
245→        $key = is_null($key) ? config('my_project.encrypt_key') : $key;
246→        return openssl_decrypt($value, 'AES-256-ECB', $key);
247→    }
248→
249→    /**
250→     * 通过正则表达式提取出一段文本中的加密字符串进行解密。
251→     *
252→     * @param string $text 指定规则的文本
253→     * @param null|Closure $checkFunc 权限检查方法
254→     * @throws \App\Exceptions\CommonException 其他异常
255→     * @throws \App\Exceptions\CryptoException 解密出错抛出的异常
256→     * @return string 返回解密后的值，不符合指定格式返回原始字符串
257→     */
258→    public function decryptText(string $text, ?Closure $checkFunc = null): string
259→    {
260→        $matches = [];
261→        if (!preg_match_all($this->pattern, $text, $matches)) {
262→            // 没有匹配到要解密的文本，直接返回密文
263→            return $text;
264→        }
265→
266→        // $matches[0]: 数组，包含所有匹配到的完整字符串
267→        // $matches[1]: 数组，包含每个匹配结果在正则表达式中第一个括号对应的部分，是要对解密值执行的转换操作
268→        // $matches[2]: 数组，包含每个匹配结果在正则表达式中第二个括号对应的部分，是要解密的加密值
269→        $origStrList = $matches[0];
270→        $methodList = $matches[1];
271→        $enValueList = $matches[2];
272→
273→        for ($i = 0; $i < count($origStrList); ++$i) {
274→            $decryptedValue = $this->decryptValue($enValueList[$i], $checkFunc);
275→            $transferredValue = $this->transferAfterDecrypt($decryptedValue, $methodList[$i]);
276→            // 替换匹配到的原字符串（替换了多个也不会有问题）
277→            $text = str_replace($origStrList[$i], $transferredValue, $text);
278→        }
279→
280→        return $text;
281→    }
282→
283→    /**
284→     * 非对称解密，默认 value 是 base64_encode 过的.
285→     *
286→     * @param string $value
287→     * @param string $privateKey
288→     * @return null|string
289→     */
290→    public function decryptByRsa(string $value, string $privateKey = ''): ?string
291→    {
292→        if ($value === '') { // 空值不必解密
293→            return '';
294→        }
295→
296→        $privateKey = empty($privateKey) ? file_get_contents(base_path(config('my_project.RSA_private_key'))) : $privateKey;
297→        openssl_private_decrypt(base64_decode($value), $decryptedValue, $privateKey);
298→        return $decryptedValue;
299→    }
300→
301→    /**
302→     * 根据配置信息来确定不同的权限检查方法。
303→     *
304→     * @param array $conf 解密配置信息
305→     * @param string $operation 需要执行的操作，response 或者 send_email
306→     * @throws \App\Exceptions\CommonException|\App\Exceptions\UserException 通用异常
307→     * @return \Closure 返回一个闭包，用于保证解密操作的合法性
308→     */
309→    protected function getCheckFunc(array $conf, string $operation): Closure
310→    {
311→        if (!empty($conf['tokens'])) {
312→            $tokenMd = AuthorizeService::app()->mergeTokens($conf['tokens'], $operation, false); // check operation 移动到 checkFunc 里面了
313→            // 解密后检查 token 的资源权限
314→            $checkFunc = function (ResourceMd $resMd) use ($tokenMd, $operation) {
315→                if (is_null($tokenMd)) {
316→                    throw new CryptoException('', CryptoException::ERR_CRYPTO_INVALID_TOKEN_ITEM);
317→                }
318→                $tokenMd->checkOperation($operation);
319→                ResourceService::app()->checkTokenPermission($resMd, $tokenMd, true);
320→            };
321→        } elseif (!empty($conf['receivers'])) {
322→            // 检查收件人的资源权限，仅限于发送消息的操作
323→            if ($operation !== 'send_email') {
324→                throw new CommonException('operation can only be send_email when provide receivers', ExceptionCode::ERR_COMMON_INVALID_ARGUMENTS);
325→            }
326→
327→            $receivers = $conf['receivers'];
328→            $checkFunc = function (ResourceMd $resMd) use ($receivers) {
329→                ResourceService::app()->checkReceiverPermission($resMd, $receivers);
330→            };
331→        } else {
332→            // 检查当前用户的资源权限
333→            $checkFunc = function (ResourceMd $resMd) {
334→                ResourceService::app()->checkUserPermission($resMd);
335→            };
336→        }
337→
338→        return $checkFunc;
339→    }
340→
341→    /**
342→     * 对解密值执行指定的转换操作。
343→     *
344→     * @param mixed $value 原始值
345→     * @param string $method 支持带参数
346→     * @throws \App\Exceptions\CommonException method 非法时抛出一个异常
347→     * @return mixed 转换后的值
348→     */
349→    protected function transferAfterDecrypt($value, string $method)
350→    {
351→        $segs = explode(':', $method, 2);
352→        if (count($segs) == 2) {
353→            $method = $segs[0];
354→            $param = $segs[1];
355→        }
356→
357→        switch ($method) {
358→            case 'base64encode':
359→                return base64_encode($value);
360→            case 'base64decode':
361→                return base64_decode($value);
362→            case 'urlencodebase64encode':
363→                return base64_encode(urlencode($value));
364→            case 'base64decodeurldecode':
365→                return urldecode(base64_encode($value));
366→            // 例：translateValue:["无","男","女"] translateValue:{"Y":"是","N":"否"}
367→            case 'translateValue':
368→                if (isset($param)) {
369→                    $map = json_decode($param, true);
370→                }
371→                return $map[$value] ?? $value;
372→            case 'nothing':
373→                return $value;
374→            default:
375→                throw new CommonException("transfer method error: {$method}", ExceptionCode::ERR_COMMON_INVALID_ARGUMENTS);
376→        }
377→    }
378→}
