314→    public function sessionMessages(Request $request): JsonResponse
315→    {
316→        $sfuserId = Arr::get($request->input('sfuser_info'), 'id');
317→        if (!$this->inWhitelist($sfuserId)) {
318→            return $this->responseJsonFail('无权限');
