320→        $sessionId = $request->input('session_id');
321→
322→        // 校验会话归属
323→        $session = DB::table('daily_report_ai_sessions')
324→            ->where('id', $sessionId)
325→            ->where('sfuser_id', $sfuserId)
326→            ->whereNull('deleted_at')
327→            ->first();
328→
329→        if (!$session) {
330→            return $this->responseJsonSuccess(['list' => []]);
331→        }
332→
333→        $contextMaxChars = 5000;
334→        $messages = DB::table('daily_report_ai_messages')
335→            ->where('session_id', $sessionId)
336→            ->orderBy('id')
337→            ->get(['id', 'role', 'content', 'created_at']);
338→
339→        // context 消息截断，减少首次加载体积
340→        foreach ($messages as $msg) {
341→            if ($msg->role === 'context') {
342→                $fullLength = mb_strlen($msg->content);
343→                if ($fullLength > $contextMaxChars) {
344→                    $msg->content = mb_substr($msg->content, 0, $contextMaxChars);
345→                    $msg->is_truncated = true;
346→                    $msg->full_length = $fullLength;
347→                }
348→            }
349→        }
350→
351→        return $this->responseJsonSuccess(['list' => $messages]);
352→    }
