474→        $groupList = !empty($availableGroups)
475→            ? implode("\n", array_map(fn ($g) => "   - {$g}", $availableGroups))
476→            : '   - （无可用分组）';
477→        $memberList = !empty($availableMembers)
478→            ? implode('、', $availableMembers)
479→            : '（无可用成员列表）';
480→        // 上次查询上下文：首次查询时为"无"，续查时包含上次的成员和周期
481→        $prevCtx = '无（首次查询）';
482→        if (!empty($previousContext)) {
483→            $prevMembers = implode('、', $previousContext['members'] ?? []);
484→            $prevType = ($previousContext['member_type'] ?? '') === 'group' ? '分组' : '成员';
485→            $prevPeriod = ($previousContext['period_start'] ?? '').' ~ '.($previousContext['period_end'] ?? '');
486→            $prevCtx = "上次查询{$prevType}：{$prevMembers}，周期：{$prevPeriod}";
487→        }
488→        $hasContextLabel = $hasExistingContext ? '是' : '否';
489→        $systemPrompt = sprintf(self::SLOT_EXTRACTION_PROMPT, $hasContextLabel, $groupList, $memberList, now()->toDateString(), $prevCtx);
490→
491→        \Log::info('[AiSlots] request', [
492→            'sfuser_id' => $sfuserId,
493→            'message' => $message,
494→            'previous_context' => $previousContext,
495→            'available_groups' => $availableGroups,
496→            'member_count' => count($availableMembers),
497→        ]);
498→
499→        // 调用 oa-core AI 接口（替代 Dify）
500→        $corePayload = [
501→            'system_prompt' => $systemPrompt,
502→            'message' => $message,
503→            'response_mode' => 'blocking',
504→        ];
505→        \Log::info('[lbl][0416-AI日报][extractSlots] 发给oa-core的请求参数', [
506→            'url' => 'master-api/ai/chat',
507→            'payload' => $corePayload,
508→        ]);
509→        try {
510→            $aiResponse = \App\Lib\Facade\CoreApiLib::sendRequest('master-api/ai/chat', $corePayload);
511→        } catch (\Throwable $e) {
512→            \Log::error('[AiSlots] oa-core AI request failed', ['error' => $e->getMessage()]);
513→            return $this->responseJsonFail('AI 接口请求失败：'.$e->getMessage());
514→        }
515→
516→        $answer = $aiResponse['data']['answer'] ?? '';
517→
518→        \Log::info('[AiSlots] response', [
519→            'sfuser_id' => $sfuserId,
520→            'answer_raw' => mb_substr($answer, 0, 1000),
521→        ]);
522→
523→        // 解析 LLM 输出的 JSON
524→        $slots = $this->parseSlotJson($answer);
525→
526→        \Log::info('[AiSlots] parsed', [
527→            'sfuser_id' => $sfuserId,
528→            'intent' => $slots['intent'],
529→            'slots_complete' => $slots['slots_complete'],
530→            'member_type' => $slots['member_type'],
531→            'members' => $slots['members'],
532→            'period' => $slots['period_start'].' ~ '.$slots['period_end'],
533→            'reply' => mb_substr($slots['reply'], 0, 200),
534→        ]);
535→
536→        return $this->responseJsonSuccess([
537→            'intent' => $slots['intent'],
538→            'slots_complete' => $slots['slots_complete'],
539→            'members' => $slots['members'],
540→            'member_type' => $slots['member_type'],
541→            'period_start' => $slots['period_start'],
542→            'period_end' => $slots['period_end'],
543→            'period_raw' => $slots['period_raw'],
544→            'reply' => $slots['reply'],
545→            'conversation_id' => '',
546→        ]);
547→    }
