549→    // ----------------------------------------------------------------
550→    // 发送消息（SSE 流式）
551→    // ----------------------------------------------------------------
552→
553→    public function ask(Request $request): StreamedResponse
554→    {
555→        $sfuserId = Arr::get($request->input('sfuser_info'), 'id');
556→        if (!$this->inWhitelist($sfuserId)) {
557→            return $this->sseError('无权限');
558→        }
559→        $roleId = $request->input('role_id');
560→        $sessionId = $request->input('session_id');
561→        $message = $request->input('message');
562→        $reportContext = $request->input('report_context', '');
563→        $reportContextRaw = $request->input('report_context_raw', '');
564→        $history = $request->input('history', []);
565→
566→        // 解压 report_context（前端 gzip+base64 压缩后以 "gz:" 前缀标识）
567→        if (str_starts_with($reportContext, 'gz:')) {
568→            $decoded = base64_decode(substr($reportContext, 3), true);
569→            $reportContext = $decoded !== false ? (gzdecode($decoded) ?: $reportContext) : $reportContext;
570→        }
571→        // 去除多余空白（连续空行压缩为单空行），减少发给 AI 的 token
572→        $reportContext = preg_replace('/\n{3,}/', "\n\n", trim($reportContext));
573→        \Log::info('[AiAsk] report_context size', [
574→            'bytes' => strlen($reportContext),
575→            'chars' => mb_strlen($reportContext),
576→        ]);
577→
578→        // 校验角色归属
579→        $role = DB::table('daily_report_ai_roles')
580→            ->where('id', $roleId)
581→            ->where('sfuser_id', $sfuserId)
582→            ->whereNull('deleted_at')
583→            ->first();
584→
585→        if (!$role) {
586→            return $this->sseError('角色不存在');
587→        }
588→
589→        // 创建或复用会话
590→        if (!$sessionId) {
591→            $title = mb_substr($message, 0, 20);
592→            $sessionId = DB::table('daily_report_ai_sessions')->insertGetId([
593→                'sfuser_id' => $sfuserId,
594→                'role_id' => $roleId,
595→                'title' => $title,
596→                'created_at' => now(),
597→                'updated_at' => now(),
598→            ]);
599→        } else {
600→            $sessionRow = DB::table('daily_report_ai_sessions')
601→                ->where('id', $sessionId)
602→                ->where('sfuser_id', $sfuserId)
603→                ->whereNull('deleted_at')
604→                ->first();
605→            if (!$sessionRow) {
606→                return $this->sseError('会话不存在');
607→            }
608→        }
609→
610→        // 解压 report_context_raw（与 report_context 相同的 gzip+base64 压缩格式）
611→        if (str_starts_with($reportContextRaw, 'gz:')) {
612→            $decoded = base64_decode(substr($reportContextRaw, 3), true);
613→            $reportContextRaw = $decoded !== false ? (gzdecode($decoded) ?: $reportContextRaw) : $reportContextRaw;
614→        }
615→
616→        // 保存同步日报上下文（如果有）—— 优先存原始 HTML，便于页面回显
617→        $contextToStore = !empty($reportContextRaw) ? $reportContextRaw : $reportContext;
618→        if (!empty($contextToStore)) {
619→            DB::table('daily_report_ai_messages')->insert([
620→                'session_id' => $sessionId,
621→                'role' => 'context',
622→                'content' => $contextToStore,
623→                'created_at' => now(),
624→            ]);
625→        }
626→
627→        // 保存用户消息
628→        DB::table('daily_report_ai_messages')->insert([
629→            'session_id' => $sessionId,
630→            'role' => 'user',
631→            'content' => $message,
632→            'created_at' => now(),
633→        ]);
634→
635→        // 更新会话时间
636→        DB::table('daily_report_ai_sessions')
637→            ->where('id', $sessionId)
638→            ->update(['updated_at' => now()]);
639→
640→        $capturedSessionId = $sessionId;
641→        $systemPrompt = $role->system_prompt;
642→
643→        return response()->stream(function () use (
644→            $message,
645→            $reportContext,
646→            $systemPrompt,
647→            $capturedSessionId,
648→            $history
649→        ) {
650→            // 客户端断开后继续执行，确保 AI 回答能写入数据库
651→            ignore_user_abort(true);
652→
653→            // 首帧：发送 session_id
654→            $this->echoData(0, '', ['type' => 'session_id', 'session_id' => $capturedSessionId]);
655→
656→            // 构建发送给 AI 的内容
657→            $queryParts = [];
658→            if (!empty($reportContext)) {
659→                $queryParts[] = "[日报数据]\n{$reportContext}";
660→            }
661→            $queryParts[] = $message;
662→            $query = implode("\n\n---\n\n", $queryParts);
663→
664→            \Log::info('[AiAsk] request', [
665→                'session' => $capturedSessionId,
666→                'query_len' => mb_strlen($query),
667→            ]);
668→
669→            // 通过 oa-core AI 接口进行流式调用（替代 Dify）
670→            $coreBaseUrl = rtrim(config('my_project.core_url', ''), '/');
671→            $aiUrl = $coreBaseUrl.'/master-api/ai/chat';
672→
673→            // 构建带签名的请求参数（与 CoreApiLib 签名逻辑一致）
674→            $coreApiSecret = config('my_project.core_api_secret');
675→            $requestParams = [
676→                'system_prompt' => $systemPrompt ?: ' ',
677→                'message' => $query,
678→                'response_mode' => 'streaming',
679→                'sys_site' => config('my_project.site_key'),
680→            ];
681→            if (!empty($history)) {
682→                $requestParams['history'] = $history;
683→            }
684→            $requestParams['sign'] = get_sign(['api_secret' => $coreApiSecret] + $requestParams, true);
685→
686→            $payload = json_encode($requestParams, JSON_UNESCAPED_UNICODE);
687→
688→            \Log::info('[lbl][0416-AI日报][ask] 发给oa-core的请求参数', [
689→                'url' => $aiUrl,
690→                'system_prompt_len' => mb_strlen($systemPrompt),
691→                'message_len' => mb_strlen($query),
692→                'history_count' => count($history),
693→                'payload' => mb_substr($payload, 0, 3000),
694→            ]);
695→
696→            $fullReply = '';
697→            $buffer = '';
698→
699→            $ch = curl_init($aiUrl);
700→            curl_setopt_array($ch, [
701→                CURLOPT_POST => true,
702→                CURLOPT_POSTFIELDS => $payload,
703→                CURLOPT_HTTPHEADER => [
704→                    'Content-Type: application/json',
705→                ],
706→                CURLOPT_RETURNTRANSFER => false,
707→                CURLOPT_TIMEOUT => 300,
708→                CURLOPT_WRITEFUNCTION => function ($curl, $data) use (&$fullReply, &$buffer) {
709→                    $buffer .= $data;
710→
711→                    while (($pos = strpos($buffer, "\n")) !== false) {
712→                        $line = rtrim(substr($buffer, 0, $pos), "\r");
713→                        $buffer = substr($buffer, $pos + 1);
714→
715→                        if (!str_starts_with($line, 'data: ')) {
716→                            continue;
717→                        }
718→
719→                        $decoded = json_decode(substr($line, 6), true);
720→                        if (!is_array($decoded)) {
721→                            continue;
722→                        }
723→
724→                        $event = $decoded['event'] ?? '';
725→
726→                        if ($event === 'message') {
727→                            $chunk = $decoded['answer'] ?? '';
728→                            if ($chunk !== '') {
729→                                $fullReply .= $chunk;
730→                                $this->echoData(0, '', ['type' => 'chat', 'is_finished' => false, 'finish_reason' => '', 'content' => $chunk]);
731→                            }
732→                        }
733→                        // message_end 表示流结束，无需处理
734→                    }
735→
736→                    return strlen($data);
737→                },
738→            ]);
739→
740→            $success = curl_exec($ch);
741→            $httpCode = curl_getinfo($ch, CURLINFO_HTTP_CODE);
742→            $curlError = $success ? '' : curl_error($ch);
743→            curl_close($ch);
744→
745→            \Log::info('[AiAsk] done', [
746→                'session' => $capturedSessionId,
747→                'http_code' => $httpCode,
748→                'curl_error' => $curlError,
749→                'reply_len' => strlen($fullReply),
750→            ]);
751→
752→            if ($curlError || empty($fullReply)) {
753→                $errMsg = $curlError ? 'AI 接口请求失败，请稍后重试' : 'AI 未返回任何内容，请稍后重试';
754→                try {
755→                    DB::reconnect();
756→                    DB::table('daily_report_ai_messages')->insert([
757→                        'session_id' => $capturedSessionId,
758→                        'role' => 'assistant',
759→                        'content' => $errMsg,
760→                        'created_at' => now(),
761→                    ]);
762→                } catch (\Throwable $e) {
763→                    \Log::error('[AiAsk] save error reply failed', ['session' => $capturedSessionId, 'error' => $e->getMessage()]);
764→                }
765→                $this->echoData(1, $errMsg, []);
766→                return;
767→            }
768→
769→            // 保存 AI 回答
770→            try {
771→                DB::reconnect();
772→                DB::statement('SET NAMES utf8mb4 COLLATE utf8mb4_unicode_ci');
773→                DB::table('daily_report_ai_messages')->insert([
774→                    'session_id' => $capturedSessionId,
775→                    'role' => 'assistant',
776→                    'content' => $fullReply,
777→                    'created_at' => now(),
778→                ]);
779→                \Log::info('[AiAsk] db save ok', ['session' => $capturedSessionId]);
780→            } catch (\Throwable $e) {
781→                \Log::error('[AiAsk] db save failed', ['session' => $capturedSessionId, 'error' => $e->getMessage()]);
782→            }
783→
784→            $this->echoData(0, '', ['type' => 'chat', 'is_finished' => true, 'finish_reason' => 'stop', 'content' => '']);
785→        }, 200, [
786→            'Content-Type' => 'text/event-stream',
787→            'Cache-Control' => 'no-cache',
788→            'X-Accel-Buffering' => 'no',
789→        ]);
790→    }
791→
792→    /**
793→     * 从 LLM 输出中解析槽位 JSON，兼容 markdown 代码块包裹.
794→     */
795→    private function parseSlotJson(string $text): array
796→    {
797→        $fallback = [
798→            'intent' => 'new_query',
799→            'slots_complete' => false,
800→            'members' => [],
801→            'member_type' => '',
802→            'period_start' => '',
803→            'period_end' => '',
804→            'period_raw' => '',
805→            'reply' => '抱歉没理解你的意思，请告诉我你想查哪个分组或具体成员的日报，以及查哪个时间段？',
806→        ];
807→
808→        if (!preg_match('/\{[\s\S]*\}/', $text, $matches)) {
809→            \Log::warning('[AiSlots] no JSON found in answer', ['text' => mb_substr($text, 0, 500)]);
810→            return $fallback;
811→        }
812→
813→        $data = json_decode($matches[0], true);
814→        if (!is_array($data)) {
815→            \Log::warning('[AiSlots] JSON parse failed', ['text' => mb_substr($matches[0], 0, 500)]);
816→            return $fallback;
817→        }
818→
819→        return [
820→            'intent' => $data['intent'] ?? 'new_query',
821→            'slots_complete' => !empty($data['slots_complete']),
822→            'members' => $data['members'] ?? [],
823→            'member_type' => $data['member_type'] ?? '',
824→            'period_start' => $data['period_start'] ?? '',
825→            'period_end' => $data['period_end'] ?? '',
826→            'period_raw' => $data['period_raw'] ?? '',
827→            'reply' => $data['reply'] ?? '',
828→        ];
829→    }
830→
831→    private function inWhitelist(int $sfuserId): bool
832→    {
833→        $setting = OaSetting::where('type', 'daily_report_ai')->select('ids', 'is_on')->first();
834→        if (!$setting || !$setting->is_on) {
835→            return false;
836→        }
837→        return in_array($sfuserId, $setting->ids ?? []);
838→    }
839→
840→    // ----------------------------------------------------------------
841→    // SSE 工具方法（同 OA echoData 规范）
842→    // ----------------------------------------------------------------
843→
844→    private function echoData(int $errCode, string $errMsg, array $data): void
845→    {
846→        echo 'data: '.json_encode(['error_code' => $errCode, 'error_msg' => $errMsg, 'data' => $data], JSON_UNESCAPED_UNICODE).PHP_EOL.PHP_EOL;
847→        ob_flush();
848→        flush();
849→    }
850→
851→    private function sseError(string $msg): StreamedResponse
852→    {
853→        return response()->stream(function () use ($msg) {
854→            $this->echoData(1, $msg, []);
855→        }, 200, [
856→            'Content-Type' => 'text/event-stream',
857→            'Cache-Control' => 'no-cache',
858→            'X-Accel-Buffering' => 'no',
859→        ]);
860→    }
861→}
