 14→class DailyReportAiEmailJob extends MyJob
 15→{
 16→    public function handle(): bool
 17→    {
 18→        $now = now();
 19→        $currentTime = $now->format('H:i');
 20→        $currentDayOfWeek = $now->dayOfWeekIso; // 1=Monday, 7=Sunday
 21→        $currentDayOfMonth = $now->day;
 22→
 23→        $tasks = DB::table('daily_report_ai_email_tasks')
 24→            ->where('is_on', 1)
 25→            ->whereNull('deleted_at')
 26→            ->where('send_time', $currentTime)
 27→            ->get();
 28→
 29→        if ($tasks->isEmpty()) {
 30→            return true;
 31→        }
 32→
 33→        foreach ($tasks as $task) {
 34→            if (!$this->shouldSendNow($task, $currentDayOfWeek, $currentDayOfMonth)) {
 35→                continue;
 36→            }
 37→
 38→            try {
 39→                $this->processTask($task);
 40→            } catch (\Throwable $e) {
 41→                info("[lbl][0416-AI日报][AiEmailJob] task={$task->id} failed: {$e->getMessage()}".$e->getTraceAsString());
 42→            }
 43→        }
 44→
 45→        info('[lbl][0416-AI日报][AiEmailJob] finished');
 46→        return true;
 47→    }
 48→
 49→    private function shouldSendNow(object $task, int $dayOfWeek, int $dayOfMonth): bool
 50→    {
 51→        $sendDay = (int)($task->send_day ?? 1);
 52→
 53→        return match ($task->send_cycle) {
 54→            'daily' => true,
 55→            'weekly' => $dayOfWeek === $sendDay,
 56→            'monthly' => $this->isMonthlyMatch($sendDay, $dayOfMonth),
 57→            default => false,
 58→        };
 59→    }
 60→
 61→    /**
 62→     * 月度匹配：如果设定日超过当月天数，则在当月最后一天触发.
 63→     */
 64→    private function isMonthlyMatch(int $sendDay, int $dayOfMonth): bool
 65→    {
 66→        $lastDayOfMonth = (int)now()->endOfMonth()->day;
 67→        $effectiveDay = min($sendDay, $lastDayOfMonth);
 68→
 69→        return $dayOfMonth === $effectiveDay;
 70→    }
 71→
 72→    private function processTask(object $task): void
 73→    {
 74→        $sfuserId = $task->sfuser_id;
 75→
 76→        // 读取邮箱配置
 77→        $mc = MailConfig::where('type', "daily_report_{$sfuserId}")->first();
 78→        if (!$mc || empty(Arr::get($mc->config, 'to_email'))) {
 79→            info("[lbl][0416-AI日报][AiEmailJob] task={$task->id} no email config, skip");
 80→            return;
 81→        }
 82→
 83→        $toEmails = Arr::get($mc->config, 'to_email');
 84→        $sfuserToken = Arr::get($mc->config, 'sfuser_authorized_token', '');
 85→        if (!$sfuserToken) {
 86→            info("[lbl][0416-AI日报][AiEmailJob] task={$task->id} no sfuser_token, skip");
 87→            return;
 88→        }
 89→
 90→        // 确定日报日期范围
 91→        [$startDate, $endDate] = $this->getDateRange($task->report_range);
 92→
 93→        // 拉取该用户能看到日报的全部员工（维度只决定分组方式）
 94→        $dailyService = app(DailyReportService::class);
 95→        $subordinates = $dailyService->getSubordinates($sfuserId);
 96→        $targetUserIds = array_unique(array_merge(
 97→            $subordinates['direct_subordinates'],
 98→            $subordinates['depart_subordinates'],
 99→            $subordinates['other_subordinates'],
100→            $subordinates['focus_users'],
101→            $subordinates['group_users']
102→        ));
103→
104→        if (empty($targetUserIds)) {
105→            info("[lbl][0416-AI日报][AiEmailJob] task={$task->id} no visible users, skip");
106→            return;
107→        }
108→
109→        // 拉取日报数据
110→        $data = $dailyService->getOthersDailyReportListEnable(
111→            $startDate,
112→            $endDate,
113→            $sfuserId,
114→            $targetUserIds,
115→            10000
116→        );
117→
118→        if (empty($data) || empty($data['reports']) || empty($data['reports']['report_list'])) {
119→            info("[lbl][0416-AI日报][AiEmailJob] task={$task->id} no report data, skip");
120→            return;
121→        }
122→
123→        $reportList = $data['reports']['report_list'];
124→
125→        // 收集所有日报涉及的 sfuser_id
126→        $reportSfuserIds = array_unique(array_column($reportList, 'sfuser_id'));
127→
128→        // 查询分组信息：按部门需要 department_id + department_name，按直接主管需要 direct_supervisor_id + direct_supervisor_nickname
129→        $sfuserGroupMap = $this->buildGroupMap($reportSfuserIds, $task->dimension);
130→
131→        // 按维度分组日报
132→        $grouped = [];
133→        foreach ($reportList as $report) {
134→            $uid = $report['sfuser_id'];
135→            $groupKey = $sfuserGroupMap[$uid]['key'] ?? 'unknown';
136→            $grouped[$groupKey]['name'] = $sfuserGroupMap[$uid]['name'] ?? '未知';
137→            $grouped[$groupKey]['reports'][] = $report;
138→        }
139→
140→        info("[lbl][0416-AI日报][AiEmailJob] task={$task->id} dimension={$task->dimension}, groups=".count($grouped));
141→
142→        // 每个分组独立发送一封邮件，各自独立 AI 分析
143→        foreach ($grouped as $groupKey => $group) {
144→            $groupName = $group['name'];
145→            $reports = $group['reports'];
146→
147→            $content = '';
148→            $no = 0;
149→            foreach ($reports as $report) {
150→                $nickname = $report['data']['nickname'] ?? '';
151→                if (empty($nickname)) {
152→                    continue;
153→                }
154→                $nickname = EncryptService::app()->markEncrString(e($nickname));
155→                $reportContent = EncryptService::app()->markEncrString($report['content']);
156→                ++$no;
157→                $content .= '<p><b>'.$no.'、 '.$nickname.'</b></p>';
158→                $content .= '<div style="border:1px solid #eee;padding:8px;margin-bottom:12px;">'.$reportContent.'</div>';
159→            }
160→
161→            if ($no === 0) {
162→                continue;
163→            }
164→
165→            $dimensionLabel = $task->dimension === 'direct_manager' ? '直属主管' : '部门';
166→            $subject = "【{$startDate}】 {$task->name}（{$dimensionLabel}：{$groupName}）- AI 分析";
167→
168→            $params = [
