194→    /**
195→     * 根据维度构建 sfuser_id => ['key' => 分组键, 'name' => 分组名] 的映射.
196→     */
197→    private function buildGroupMap(array $sfuserIds, string $dimension): array
198→    {
199→        if (empty($sfuserIds)) {
200→            return [];
201→        }
202→
203→        $map = [];
204→
205→        if ($dimension === 'direct_manager') {
206→            // 按直接主管分组
207→            $users = Sfuser::whereIn('id', $sfuserIds)
208→                ->select('id', 'direct_supervisor_id', 'direct_supervisor_nickname')
209→                ->get();
210→
211→            foreach ($users as $user) {
212→                $managerId = $user->direct_supervisor_id ?: 0;
213→                $managerName = $user->direct_supervisor_nickname ?: '无直接主管';
214→                $map[$user->id] = [
215→                    'key' => "mgr_{$managerId}",
216→                    'name' => $managerName,
217→                ];
218→            }
219→        } else {
220→            // 按部门分组
221→            $users = Sfuser::whereIn('id', $sfuserIds)
222→                ->select('id', 'department_id')
223→                ->get();
224→
225→            // 批量查部门名称
226→            $deptIds = $users->pluck('department_id')->filter()->unique()->values()->toArray();
227→            $deptNames = [];
228→            if (!empty($deptIds)) {
229→                $deptNames = DB::table('job_departments')
230→                    ->whereIn('id', $deptIds)
231→                    ->pluck('name', 'id')
232→                    ->toArray();
233→            }
234→
235→            foreach ($users as $user) {
236→                $deptId = $user->department_id ?: 0;
237→                $deptName = $deptNames[$deptId] ?? '未分配部门';
238→                $map[$user->id] = [
239→                    'key' => "dept_{$deptId}",
240→                    'name' => $deptName,
241→                ];
242→            }
243→        }
244→
245→        return $map;
246→    }
