248→    private function getDateRange(string $reportRange): array
249→    {
250→        $today = now()->toDateString();
251→        return match ($reportRange) {
252→            'last_3_days' => [now()->subDays(2)->toDateString(), $today],
253→            'last_7_days' => [now()->subDays(6)->toDateString(), $today],
254→            default => [$today, $today],
255→        };
256→    }
