 3→namespace App\Http\Middleware;
 4→
 5→use App\Exceptions\CommonException;
 6→use App\Http\ResponseTrait;
 7→use Closure;
 8→use Illuminate\Http\Request;
 9→
10→class CheckMasterApi
11→{
12→    use ResponseTrait;
13→
14→    /**
15→     * Handle an incoming request.
16→     *
17→     * @param \Illuminate\Http\Request $request
18→     * @param \Closure $next
19→     * @throws \App\Exceptions\CommonException
20→     * @return mixed
21→     */
22→    public function handle(Request $request, Closure $next): mixed
23→    {
24→        // 统一打印一条请求日志，方便debug
25→        if (!$request->input('disable_log')) {
26→            info('Request: '.request()->path().', Params: '.my_json_encode($request->all()).', IP: '.$request->ip());
27→        }
28→
29→        $this->checkSign($request->all(), config('my_project.master_api_secret'));
30→
31→        $api_info = current_api_info();
32→        // 检查传入的参数是否符合要求
33→        if (!empty($api_info['params'])) {
34→            $validator = validator($request->all(), $api_info['params']);
35→            if ($validator->fails()) {
36→                return $this->responseJsonFail(implode(' ', $validator->errors()->all()), CommonException::ERR_COMMON_INVALID_ARGUMENTS);
37→            }
38→        }
39→
40→        return $next($request);
41→    }
42→
43→    /**
44→     * 检查签名，确保请求参数未被篡改。
45→     *
46→     * @param array $params
47→     * @param string $apiSecret
48→     * @throws \App\Exceptions\CommonException
49→     * @return void
50→     */
51→    protected function checkSign(array $params, string $apiSecret): void
52→    {
53→        if (empty($params['sign'])) {
54→            throw new CommonException('lacking parameter: sign', CommonException::ERR_COMMON_MISSING_PARAMETERS);
55→        }
56→
57→        $sign = $params['sign'];
58→        $newSign = get_sign($params, $apiSecret);
59→        if ($sign !== $newSign) {
60→            info(sprintf('mismatched sign, given: %s, expected: %s', $sign, $newSign));
61→            throw new CommonException('check sign failed', CommonException::ERR_COMMON_INVALID_ARGUMENTS);
62→        }
63→    }
64→}
